import 'package:firebase_crashlytics/firebase_crashlytics.dart'; import 'package:injectable/injectable.dart'; @singleton class CrashReportingService { bool _enabled = true; bool get isEnabled => _enabled; Future<void> enable() async { _enabled = true; await FirebaseCrashlytics.instance.setCrashlyticsCollectionEnabled(true); } Future<void> disable() async { _enabled = false; await FirebaseCrashlytics.instance.setCrashlyticsCollectionEnabled(false); } Future<void> report(dynamic e, StackTrace? s) { if (!_enabled) return Future.value(); return FirebaseCrashlytics.instance.recordError(e, s); } }